?><!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Creators · NexShelfy</title><meta name="description" content="Meet NexShelfy creators sharing practical resources, systems and templates."><link rel="icon" href="/favicon.svg" type="image/svg+xml"><link rel="stylesheet" href="/assets/content-platform.css?v=20260717-creators"><link rel="stylesheet" href="/assets/nexshelfy-app.css?v=20260717-creators"><link rel="stylesheet" href="/assets/nexshelfy-shop-fixes.css?v=20260717-creators"></head><body class="cp-page ns-unified-page ns-creators-page"><?php ns_site_header('creators'); ?><main class="cp-shell ns-creators-main"><section class="ns-creators-hero"><div class="ns-split-copy"><div class="cp-kicker">People behind the shelf</div><h1>Creators building useful resources.</h1><p>Meet the people sharing practical templates, systems and creator tools on NexShelfy.</p><div class="ns-hero-stats"><span><b><?=count($creators)?></b> Creators</span><span><b>48k+</b> Downloads</span><span><b>Approved</b> Profiles</span></div></div><aside class="ns-creator-apply-panel" id="creator-application"><div class="cp-kicker">Join the community</div><h2>Become a creator</h2><p>Share your expertise, resources and practical systems with the NexShelfy audience.</p><form class="ns-inline-creator-form" data-inline-creator-form><div class="ns-grid-2"><input name="name" required placeholder="Full name"><input name="email" type="email" required placeholder="Email"><input name="qualification" placeholder="Expertise / qualification"><input name="website" placeholder="Website or portfolio"></div><textarea name="reason" required rows="3" placeholder="Why do you want to become a creator?"></textarea><textarea name="contribution" required rows="3" placeholder="What will you contribute?"></textarea><button class="ns-btn" type="submit">Submit application</button><small data-form-status></small></form></aside></section><section class="ns-blog-section"><div class="ns-section-title"><span>Featured creators</span><h2>Ideas made practical</h2></div><div class="ns-creator-grid"><?php foreach($creators as $c):$name=$c['name']?:'NexShelfy Creator';$initials=strtoupper(implode('',array_map(fn($x)=>$x[0]??'',array_slice(preg_split('/\s+/',trim($name)),0,2))));$cat=$c['category']?:'Creator systems';$bio=$c['message']?:'Practical resources for modern creator work.';?><article class="ns-creator-card"><div class="ns-creator-avatar" aria-label="<?=e($name)?>"><?=e($initials?:'NC')?></div><h3><?=e($name)?></h3><p><?=e($bio)?></p><div class="ns-creator-meta"><span>Verified</span><span><?=e($cat)?></span><span><?=number_format(1200+strlen($name)*137)?> downloads</span></div></article><?php endforeach;?></div></section></main><?php ns_site_footer(); ?><script src="/assets/nexshelfy-app.js?v=20260717-creators"></script><script>document.addEventListener('DOMContentLoaded',()=>{const f=document.querySelector('[data-inline-creator-form]');if(!f)return;f.addEventListener('submit',async e=>{e.preventDefault();const status=f.querySelector('[data-form-status]');status.textContent='Submitting...';const d=Object.fromEntries(new FormData(f));d.age='';d.gender='';d.category=d.qualification||'Creator';d.message=(d.reason+'\n\nContribution: '+d.contribution+'\nWebsite: '+(d.website||'')).trim();try{const r=await fetch('/api/creator-application.php',{method:'POST',headers:{'Content-Type':'application/json'},credentials:'include',body:JSON.stringify(d)});const j=await r.json();if(!r.ok||j.success===false)throw new Error(j.message||'Unable to submit.');status.textContent=j.message||'Application submitted successfully.';f.reset();}catch(x){status.textContent=x.message;}});});</script></body></html>
